#!/usr/bin/env python3
"""
深層VideoId抽出スクリプト
- ネットワークリクエストから videoId を追跡
- iFrame / embed情報を抽出
- ページ内のすべてのメタデータを解析
"""

import asyncio
import json
import sys
import os
from pathlib import Path
from datetime import datetime

if sys.platform == "win32":
    os.environ["PYTHONIOENCODING"] = "utf-8"
    sys.stdout.reconfigure(encoding="utf-8")

try:
    from playwright.async_api import async_playwright
except ImportError:
    print("❌ playwright がインストールされていません")
    sys.exit(1)

ESTIMATED_URLS = {
    "思考の原則": "https://www.awareness.co.jp/mypage/archives/study-watch/348/376/5208",
    "成長と変化の原則": "https://www.awareness.co.jp/mypage/archives/study-watch/348/376/5209",
    "繰の原則": "https://www.awareness.co.jp/mypage/archives/study-watch/348/376/5213",
    "潜在意識の原則": "https://www.awareness.co.jp/mypage/archives/study-watch/348/376/5210",
    "無限大の原則": "https://www.awareness.co.jp/mypage/archives/study-watch/348/376/5211",
}


async def extract_video_id_deep(url: str) -> dict:
    """深層VideoId抽出"""
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        context = await browser.new_context()
        page = await context.new_page()

        result = {
            "url": url,
            "video_ids": [],
            "iframes": [],
            "video_elements": [],
            "network_urls": [],
            "metadata": {},
        }

        try:
            print(f"  🔍 ページロード中...")
            await page.goto(url, timeout=15000, wait_until="networkidle")

            # ネットワークリクエストから videoId を抽出
            print(f"  📡 ネットワークリクエストをスキャン...")
            await page.evaluate('''
                () => {
                    window.capturedRequests = [];
                    const originalFetch = window.fetch;
                    window.fetch = function(...args) {
                        window.capturedRequests.push(args[0]);
                        return originalFetch.apply(this, args);
                    };
                }
            ''')

            # ページ遅延ロード（動的JavaScriptで埋め込まれた情報）
            await asyncio.sleep(2)

            captured_urls = await page.evaluate('() => window.capturedRequests || []')
            print(f"    → キャプチャ: {len(captured_urls)} リクエスト")

            # Brightcove/video APIリクエストをフィルタ
            for req_url in captured_urls:
                if isinstance(req_url, str):
                    if 'brightcove' in req_url.lower() or 'video' in req_url.lower():
                        result["network_urls"].append(req_url)
                        print(f"    → {req_url}")

                        # URLから videoId を抽出
                        if 'videoId=' in req_url:
                            vid = req_url.split('videoId=')[1].split('&')[0]
                            if vid not in result["video_ids"]:
                                result["video_ids"].append(vid)

            # iFrame から videoId を抽出
            print(f"  🎬 iFrame をスキャン...")
            iframes = await page.query_selector_all('iframe')
            for i, iframe in enumerate(iframes):
                src = await iframe.get_attribute('src')
                id_attr = await iframe.get_attribute('id')
                if src:
                    result["iframes"].append({"src": src, "id": id_attr})
                    print(f"    → iFrame {i}: {src}")
                    if 'videoId=' in src:
                        vid = src.split('videoId=')[1].split('&')[0]
                        if vid not in result["video_ids"]:
                            result["video_ids"].append(vid)

            # video 要素を検索
            print(f"  🎥 video 要素をスキャン...")
            videos = await page.query_selector_all('video')
            for i, video in enumerate(videos):
                data_video_id = await video.get_attribute('data-video-id')
                if data_video_id:
                    result["video_elements"].append(data_video_id)
                    print(f"    → video {i}: {data_video_id}")
                    if data_video_id not in result["video_ids"]:
                        result["video_ids"].append(data_video_id)

            # スクリプトタグ内のJSON から videoId を抽出
            print(f"  📝 スクリプトタグをスキャン...")
            video_data = await page.evaluate(r'''
                () => {
                    const results = [];
                    const scripts = document.querySelectorAll('script[type="application/json"], script[type="application/ld+json"]');
                    for (let s of scripts) {
                        try {
                            const data = JSON.parse(s.textContent);
                            if (data.videoId || data.video_id) {
                                results.push(data);
                            }
                        } catch (e) {}
                    }
                    return results;
                }
            ''')
            if video_data:
                result["metadata"] = video_data
                for item in video_data:
                    vid = item.get('videoId') or item.get('video_id')
                    if vid and vid not in result["video_ids"]:
                        result["video_ids"].append(str(vid))
                print(f"    → {len(video_data)} JSONデータ")

            # ページHTMLから直接 videoId を検索
            print(f"  🔎 HTML テキストをスキャン...")
            html_content = await page.content()
            import re
            video_ids_in_html = re.findall(r'["\']?videoId["\']?\s*[:\=]\s*["\']?(\d+)["\']?', html_content)
            for vid in video_ids_in_html:
                if vid not in result["video_ids"]:
                    result["video_ids"].append(vid)
            if video_ids_in_html:
                print(f"    → {len(video_ids_in_html)} videoId 発見")

        except Exception as e:
            result["error"] = str(e)
            print(f"    ❌ エラー: {e}")

        finally:
            await browser.close()

        return result


async def main():
    """メイン処理"""
    print("\n" + "="*70)
    print("深層VideoId抽出スクリプト")
    print("="*70)
    print(f"実行時刻: {datetime.now().isoformat()}\n")

    results = {}

    for title, url in ESTIMATED_URLS.items():
        print(f"\n【{title}】")
        result = await extract_video_id_deep(url)
        results[title] = result

        if result["video_ids"]:
            print(f"  ✅ VideoId 発見: {', '.join(result['video_ids'])}")
        else:
            print(f"  ⚠️  VideoId が見つかりません")

    # 結果をJSON形式で保存
    output_file = Path("deep_extraction_results.json")
    with open(output_file, "w", encoding="utf-8") as f:
        json.dump(results, f, ensure_ascii=False, indent=2)

    print("\n" + "="*70)
    print("抽出結果サマリー")
    print("="*70)

    found_count = sum(1 for r in results.values() if r["video_ids"])
    print(f"\n✅ VideoId 発見: {found_count}/{len(results)}")

    for title, result in results.items():
        if result["video_ids"]:
